"use client";

import { type KeyValueProps, KeyValue as KeyValueRoot, keyValueVariants } from "./key-value";
import type { KeyValueLayout, KeyValueVariant } from "./key-value-context";
import {
  KeyValueItem,
  type KeyValueItemProps,
  keyValueLabelVariants,
  keyValueValueVariants,
} from "./key-value-item";

const KeyValue = Object.assign(KeyValueRoot, { Item: KeyValueItem });

export { KeyValue, keyValueVariants, type KeyValueProps, type KeyValueLayout };
export {
  KeyValueItem,
  keyValueLabelVariants,
  keyValueValueVariants,
  type KeyValueItemProps,
  type KeyValueVariant,
};

"use client";

import { cva } from "class-variance-authority";
import { type ComponentPropsWithRef, type ReactNode, useMemo } from "react";
import { cn } from "@/lib/utils";
import { KeyValueContext, type KeyValueLayout } from "./key-value-context";

/** Class variants for key value. */
export const keyValueVariants = cva("grid", {
  variants: {
    layout: {
      horizontal: "grid-cols-[minmax(0,1fr)_auto] items-baseline gap-x-6 gap-y-2",
      vertical: "grid-cols-1 gap-y-1",
    },
    bordered: {
      true: "gap-y-0",
      false: "",
    },
  },
  defaultVariants: { layout: "horizontal", bordered: false },
});

/** Props for key value. */
export interface KeyValueProps extends ComponentPropsWithRef<"dl"> {
  /**
   * Horizontal places label and value side-by-side; vertical stacks them. Propagated to
   * KeyValue.Item via context.
   */
  layout?: KeyValueLayout;
  /**
   * Adds row borders and switches items to compact xs sizing. Propagated to KeyValue.Item via
   * context.
   */
  bordered?: boolean;
  /** KeyValue.Item rows rendered inside a semantic <dl>. */
  children: ReactNode;
}

/**
 * Compound component for displaying labeled data. KeyValue wraps one or more KeyValue.Item rows
 * in a semantic description list.
 */
export function KeyValue({
  layout = "horizontal",
  bordered = false,
  children,
  className,
  ref,
  ...props
}: KeyValueProps) {
  const contextValue = useMemo(() => ({ layout, bordered }), [layout, bordered]);

  return (
    <KeyValueContext value={contextValue}>
      <dl
        ref={ref}
        data-slot="key-value"
        className={cn(keyValueVariants({ layout, bordered }), className)}
        {...props}
      >
        {children}
      </dl>
    </KeyValueContext>
  );
}

"use client";

import { cva } from "class-variance-authority";
import type { ComponentPropsWithRef, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { type KeyValueLayout, type KeyValueVariant, useKeyValueContext } from "./key-value-context";

/** Props for key value item. */
export interface KeyValueItemProps extends Omit<ComponentPropsWithRef<"dt">, "children"> {
  /** Label content rendered in a <dt>. */
  label: ReactNode;
  /** Value content rendered in a <dd>. */
  value: ReactNode;
  /** Color token applied to the value. Info uses monospace; the rest are bold semantic colors. */
  variant?: KeyValueVariant;
  /** Per-row override of the parent layout. */
  layout?: KeyValueLayout;
  /** Per-row override of the parent bordered prop. */
  bordered?: boolean;
  /** Class applied to the <dt> in addition to the variant classes. */
  labelClassName?: string;
  /** Class applied to the <dd> in addition to the variant classes. */
  valueClassName?: string;
}

/** Class variants for label. */
export const keyValueLabelVariants = cva("text-muted-foreground", {
  variants: {
    bordered: {
      true: "pt-4 border-t border-border first:border-t-0 text-xs",
      false: "text-sm",
    },
  },
  defaultVariants: { bordered: false },
});

/** Class variants for value. */
export const keyValueValueVariants = cva("", {
  variants: {
    variant: {
      default: "font-bold text-foreground",
      warning: "font-bold text-warning",
      info: "font-mono text-foreground",
      success: "font-bold text-success",
      error: "font-bold text-error",
    },
    bordered: { true: "text-xs", false: "" },
    layout: {
      horizontal: "text-right",
      vertical: "pb-3",
    },
  },
  compoundVariants: [
    {
      layout: "horizontal",
      bordered: true,
      class: "pt-4 border-t border-border [&:nth-child(2)]:border-t-0",
    },
  ],
  defaultVariants: { variant: "default", bordered: false, layout: "horizontal" },
});

export function KeyValueItem({
  label,
  value,
  variant = "default",
  className,
  labelClassName,
  valueClassName,
  ref,
  layout: layoutProp,
  bordered: borderedProp,
  ...rest
}: KeyValueItemProps) {
  const ctx = useKeyValueContext();
  const layout = layoutProp ?? ctx.layout;
  const bordered = borderedProp ?? ctx.bordered;

  return (
    <>
      <dt
        ref={ref}
        className={cn(keyValueLabelVariants({ bordered }), className, labelClassName)}
        {...rest}
      >
        {label}
      </dt>
      <dd className={cn(keyValueValueVariants({ variant, bordered, layout }), valueClassName)}>
        {value}
      </dd>
    </>
  );
}

"use client";

import { createContext, useContext } from "react";

export type KeyValueLayout = "horizontal" | "vertical";
/** Allowed key value variant values. */
export type KeyValueVariant = "default" | "warning" | "info" | "success" | "error";

/** Context value shared by key value. */
interface KeyValueContextValue {
  /**
   * Horizontal places label and value side-by-side; vertical stacks them. Propagated to
   * KeyValue.Item via context.
   */
  layout: KeyValueLayout;
  /**
   * Adds row borders and switches items to compact xs sizing. Propagated to KeyValue.Item via
   * context.
   */
  bordered: boolean;
}

/** React context backing key value. */
const KeyValueContext = createContext<KeyValueContextValue | undefined>(undefined);

/** Reads the key value context. */
function useKeyValueContext(): KeyValueContextValue {
  const context = useContext(KeyValueContext);
  if (context === undefined) {
    throw new Error("KeyValue.Item must be used within KeyValue");
  }
  return context;
}

export { KeyValueContext, useKeyValueContext };
